import React, { useState } from 'react';

const Fees = () => {
  const [activeTab, setActiveTab] = useState('structure');
  const [searchTerm, setSearchTerm] = useState('');
  const [version, setVersion] = useState(Date.now());

  // Force reload if currency formatting is updated
  useEffect(() => {
    const checkVersion = () => {
      const currentVersion = localStorage.getItem('fees-page-version');
      if (!currentVersion || parseInt(currentVersion) < 171517904000) {
        console.log('New version detected, reloading...');
        localStorage.setItem('fees-page-version', '171517904000');
        window.location.reload();
      }
    };

    checkVersion();
  }, []);

  // Sample fee structures
  const feeStructures = [
    {
      id: 1,
      name: 'B.Tech Computer Science',
      semester: 'Semester 1',
      totalFees: 125000,
      breakdown: {
        tuition: 75000,
        library: 5000,
        laboratory: 10000,
        examination: 3000,
        development: 5000,
        alumni: 5000,
        hostel: 22000
      }
    },
    {
      id: 2,
      name: 'M.B.A Business Administration',
      semester: 'Semester 1',
      totalFees: 95000,
      breakdown: {
        tuition: 60000,
        library: 3000,
        examination: 2500,
        development: 3000,
        alumni: 2500,
        other: 24000
      }
    },
    {
      id: 3,
      name: 'B.Sc Physics',
      semester: 'Semester 1',
      totalFees: 110000,
      breakdown: {
        tuition: 70000,
        library: 2000,
        laboratory: 15000,
        examination: 3000,
        development: 2000,
        alumni: 2000,
        other: 16000
      }
    }
  ];

  // Sample payment history
  const paymentHistory = [
    {
      id: 1,
      studentName: 'Rahul Kumar',
      course: 'B.Tech Computer Science',
      semester: 'Semester 1',
      amount: 125000,
      paymentDate: '2024-01-15',
      status: 'Paid',
      transactionId: 'TXN123456789'
    },
    {
      id: 2,
      studentName: 'Priya Sharma',
      course: 'M.B.A Business Administration',
      semester: 'Semester 1',
      amount: 47500,
      paymentDate: '2024-01-20',
      status: 'Paid',
      transactionId: 'TXN123456790'
    },
    {
      id: 3,
      studentName: 'Amit Singh',
      course: 'B.Sc Physics',
      semester: 'Semester 1',
      amount: 55000,
      paymentDate: '2024-01-25',
      status: 'Partial',
      transactionId: 'TXN123456791'
    }
  ];

  const formatCurrency = (amount) => {
    console.log('Testing currency formatting:', amount, '→', new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: 'INR',
      minimumFractionDigits: 0
    }).format(amount));
    return new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: 'INR',
      minimumFractionDigits: 0
    }).format(amount);
  };

  const filteredStructures = feeStructures.filter(fee => 
    fee.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    fee.course.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const filteredPayments = paymentHistory.filter(payment =>
    payment.studentName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    payment.course.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div>
      <h1 className="text-2xl font-bold text-gray-900 mb-6">Fees Management</h1>

      {/* Search Bar */}
      <div className="mb-6">
        <div className="max-w-md mx-auto">
          <input
            type="text"
            placeholder="Search by student name or course..."
            className="input"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
      </div>

      {/* Tab Navigation */}
      <div className="border-b border-gray-200">
        <nav className="-mb-px flex space-x-8">
          <button
            onClick={() => setActiveTab('structure')}
            className={`py-2 px-1 border-b-2 font-medium text-sm ${
              activeTab === 'structure'
                ? 'border-blue-500 text-blue-600'
                : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
            }`}
          >
            Fee Structure
          </button>
          <button
            onClick={() => setActiveTab('payments')}
            className={`py-2 px-1 border-b-2 font-medium text-sm ${
              activeTab === 'payments'
                ? 'border-blue-500 text-blue-600'
                : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
            }`}
          >
            Payment History
          </button>
        </nav>
      </div>

      {/* Content based on active tab */}
      {activeTab === 'structure' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredStructures.map((fee) => (
            <div key={fee.id} className="bg-white shadow rounded-lg p-6">
              <h3 className="text-lg font-semibold text-gray-900 mb-4">{fee.name}</h3>
              <p className="text-sm text-gray-600 mb-4">{fee.semester}</p>

              <div className="space-y-3">
                <div className="flex justify-between items-center py-2 border-b">
                  <span className="text-gray-600">Tuition Fees</span>
                  <span className="font-semibold">{formatCurrency(fee.breakdown.tuition)}</span>
                </div>
                <div className="flex justify-between items-center py-2 border-b">
                  <span className="text-gray-600">Library Fees</span>
                  <span className="font-semibold">{formatCurrency(fee.breakdown.library)}</span>
                </div>
                <div className="flex justify-between items-center py-2 border-b">
                  <span className="text-gray-600">Laboratory Fees</span>
                  <span className="font-semibold">{formatCurrency(fee.breakdown.laboratory)}</span>
                </div>
                <div className="flex justify-between items-center py-2 border-b">
                  <span className="text-gray-600">Examination Fees</span>
                  <span className="font-semibold">{formatCurrency(fee.breakdown.examination)}</span>
                </div>
                <div className="flex justify-between items-center py-2 border-b">
                  <span className="text-gray-600">Development Fees</span>
                  <span className="font-semibold">{formatCurrency(fee.breakdown.development)}</span>
                </div>
                <div className="flex justify-between items-center py-2 border-b">
                  <span className="text-gray-600">Alumni Fees</span>
                  <span className="font-semibold">{formatCurrency(fee.breakdown.alumni)}</span>
                </div>
                <div className="flex justify-between items-center py-2">
                  <span className="text-gray-600">Hostel Fees</span>
                  <span className="font-semibold">{formatCurrency(fee.breakdown.hostel)}</span>
                </div>
                <div className="flex justify-between items-center py-2">
                  <span className="text-gray-600">Other Fees</span>
                  <span className="font-semibold">{formatCurrency(fee.breakdown.other)}</span>
                </div>
              </div>

              <div className="mt-4 pt-4 border-t">
                <div className="flex justify-between items-center">
                  <span className="text-lg font-bold text-gray-900">Total Fees</span>
                  <span className="text-xl font-bold text-blue-600">{formatCurrency(fee.totalFees)}</span>
                </div>
              </div>

              <div className="mt-4 flex space-x-3">
                <button className="btn btn-primary">Edit Structure</button>
                <button className="btn btn-secondary">Print Receipt</button>
              </div>
            </div>
          ))}
        </div>
      )}

      {activeTab === 'payments' && (
        <div className="bg-white shadow rounded-lg">
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Transaction ID</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Student Name</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Course</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Amount</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Date</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Status</th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {filteredPayments.map((payment) => (
                  <tr key={payment.id}>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                      {payment.transactionId}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      {payment.studentName}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      {payment.course}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-semibold text-gray-900">
                      {formatCurrency(payment.amount)}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      {payment.paymentDate}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full ${
                        payment.status === 'Paid' ? 'bg-green-100 text-green-800' : 'bg-yellow-100 text-yellow-800'
                      }`}>
                        {payment.status}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <div className="mt-6 flex justify-between items-center">
            <div className="text-sm text-gray-600">
              Showing {filteredPayments.length} of {paymentHistory.length} payments
            </div>
            <button className="btn btn-primary">Export to Excel</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default Fees;
